export default function Logo({ className }: { className?: string }) {
  const [isDark, setIsDark] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    // Check if dark class is present on HTML element
    const checkTheme = () => {
      const isDarkMode = document.documentElement.classList.contains("dark");
      setIsDark(isDarkMode);
    };

    // Check initial theme
    checkTheme();
    setMounted(true);

    // Watch for theme changes
    const observer = new MutationObserver(checkTheme);
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ["class"],
    });

    return () => observer.disconnect();
  }, []);

  // Prevent hydration mismatch
  if (!mounted) {
    return (
      <div className={cn(
        "flex items-center justify-start h-[var(--header-height)] px-4",
        className
      )}>
        <div className="h-12 w-48 bg-muted animate-pulse rounded" />
      </div>
    );
  }

  return (
    <Link
      href="/"
      className={cn(
        "flex items-center justify-start h-[var(--header-height)]",
        "hover:opacity-80 transition-opacity",
        className
      )}
    >
      <div
        className="h-auto w-auto max-h-12 [&>svg]:h-auto [&>svg]:w-auto [&>svg]:max-h-12 logo-svg-container"
        dangerouslySetInnerHTML={{
          __html: isDark ? darkSvg : lightSvg,
        }}
      />
    </Link>
  );
}
